import { useState } from 'react';

export default function Store() {
  const [selectedItem, setSelectedItem] = useState(null);
    const [formData, setFormData] = useState({
        username: '',
            bKashNumber: '',
                transactionId: '',
                  });
                    const [loading, setLoading] = useState(false);
                      const [status, setStatus] = useState('');

                        const DISCORD_WEBHOOK_URL = "https://discord.com/api/webhooks/1529055875027697666/OWBIewyPTHwlvm3b6JbDyKqoz5LDTOMZVJwAXOmctZU4dK3YOv3yqbJkraqSCBdIU8jC";

                          // স্টোরের আইটেমগুলোর তালিকা
                            const items = [
                                { id: 1, name: "Monthly Membership", price: 100, desc: "Get full perks, monthly crate keys, and priority queue access." },
                                    { id: 2, name: "Diamond Sword", price: 50, desc: "Sharpness V + Strength Boost" },
                                        { id: 3, name: "Lucky Crate Key", price: 30, desc: "Open at spawn for random epic loot" },
                                          ];

                                            const handleSubmit = async (e) => {
                                                e.preventDefault();
                                                    setLoading(true);
                                                        setStatus('');

                                                            const embedData = {
                                                                  embeds: [
                                                                          {
                                                                                    title: "🛒 নতুন বিকাশ পেমেন্ট রিকোয়েস্ট!",
                                                                                              color: 5763719, // Green
                                                                                                        fields: [
                                                                                                                    { name: "📦 আইটেম/প্যাকেজ", value: selectedItem.name, inline: true },
                                                                                                                                { name: "💰 টাকার পরিমাণ", value: `${selectedItem.price} BDT`, inline: true },
                                                                                                                                            { name: "👤 Minecraft IGN", value: formData.username, inline: false },
                                                                                                                                                        { name: "📱 বিকাশ নাম্বার", value: formData.bKashNumber, inline: true },
                                                                                                                                                                    { name: "🧾 Transaction ID (TrxID)", value: formData.transactionId, inline: true },
                                                                                                                                                                              ],
                                                                                                                                                                                        timestamp: new Date().toISOString(),
                                                                                                                                                                                                },
                                                                                                                                                                                                      ],
                                                                                                                                                                                                          };

                                                                                                                                                                                                              try {
                                                                                                                                                                                                                    const response = await fetch(DISCORD_WEBHOOK_URL, {
                                                                                                                                                                                                                            method: 'POST',
                                                                                                                                                                                                                                    headers: { 'Content-Type': 'application/json' },
                                                                                                                                                                                                                                            body: JSON.stringify(embedData),
                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                        if (response.ok) {
                                                                                                                                                                                                                                                                setStatus('success');
                                                                                                                                                                                                                                                                        setFormData({ username: '', bKashNumber: '', transactionId: '' });
                                                                                                                                                                                                                                                                              } else {
                                                                                                                                                                                                                                                                                      setStatus('error');
                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                } catch (err) {
                                                                                                                                                                                                                                                                                                      setStatus('error');
                                                                                                                                                                                                                                                                                                          } finally {
                                                                                                                                                                                                                                                                                                                setLoading(false);
                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                      };

                                                                                                                                                                                                                                                                                                                        return (
                                                                                                                                                                                                                                                                                                                            <div className="min-h-screen bg-gray-900 text-white p-6 flex flex-col items-center">
                                                                                                                                                                                                                                                                                                                                  <h1 className="text-3xl font-bold mb-2 text-center text-green-400">In-Game Store</h1>
                                                                                                                                                                                                                                                                                                                                        <p className="text-gray-400 text-sm mb-8 text-center">আপনার পছন্দের প্যাকেজ সিলেক্ট করে বিকাশ সেন্ড মানি করুন</p>

                                                                                                                                                                                                                                                                                                                                              {/* Item List */}
                                                                                                                                                                                                                                                                                                                                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-4xl w-full mb-10">
                                                                                                                                                                                                                                                                                                                                                            {items.map((item) => (
                                                                                                                                                                                                                                                                                                                                                                      <div key={item.id} className="bg-gray-800 border border-gray-700 rounded-xl p-5 flex flex-col justify-between shadow-lg">
                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                <h3 className="text-xl font-bold text-white mb-1">{item.name}</h3>
                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-gray-400 text-xs mb-4">{item.desc}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="text-lg font-bold text-green-400 mb-3">{item.price} tk</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onClick={() => { setSelectedItem(item); setStatus(''); }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-2 rounded-lg transition"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Purchase
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* Payment Modal / Form Section */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {selectedItem && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="fixed inset-0 bg-black/80 flex items-center justify-center p-4 z-50">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="bg-gray-800 p-6 rounded-xl max-w-md w-full border border-gray-700 relative">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onClick={() => setSelectedItem(null)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="absolute top-3 right-3 text-gray-400 hover:text-white font-bold text-xl"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ✕
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <h2 className="text-xl font-bold text-green-400 mb-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {selectedItem.name} ({selectedItem.price} BDT)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <p className="text-xs text-gray-400 mb-4">পেমেন্ট সম্পন্ন করে নিচের তথ্য জমা দিন</p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {/* Instruction */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="bg-gray-900 border border-green-500/40 p-3 rounded-lg mb-4 text-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-xs text-gray-300">বিকাশ পার্সোনাল (Send Money):</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="text-lg font-mono font-bold text-green-400 my-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    01978020786
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <p className="text-[11px] text-gray-400">পাঠাতে হবে: <span className="text-white font-bold">{selectedItem.price} TK</span></p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {status === 'success' ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="bg-green-600/20 border border-green-500 text-green-300 p-3 rounded-lg text-xs text-center mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ✅ পেমেন্ট সাবমিট হয়েছে! এডমিন খুব শীঘ্রই চেক করে আইটেম দিয়ে দিবে।
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ) : status === 'error' ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="bg-red-600/20 border border-red-500 text-red-300 p-3 rounded-lg text-xs text-center mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ❌ সাবমিট করতে সমস্যা হয়েছে, আবার চেষ্টা করুন।
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ) : null}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <form onSubmit={handleSubmit} className="flex flex-col gap-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <label className="block text-xs text-gray-300 mb-1">Minecraft In-Game Name (IGN):</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    type="text"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      required
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        placeholder="e.g. Player_Name"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          value={formData.username}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className="w-full p-2 bg-gray-700 border border-gray-600 rounded text-sm text-white focus:outline-none focus:border-green-500"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <label className="block text-xs text-gray-300 mb-1">আপনার বিকাশ নাম্বার:</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            type="text"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              required
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                placeholder="019xxxxxxxx"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  value={formData.bKashNumber}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onChange={(e) => setFormData({ ...formData, bKashNumber: e.target.value })}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      className="w-full p-2 bg-gray-700 border border-gray-600 rounded text-sm text-white focus:outline-none focus:border-green-500"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <label className="block text-xs text-gray-300 mb-1">TrxID (ট্রানজেকশন আইডি):</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    type="text"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      required
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        placeholder="e.g. BK98X76YZ"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          value={formData.transactionId}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={(e) => setFormData({ ...formData, transactionId: e.target.value })}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className="w-full p-2 bg-gray-700 border border-gray-600 rounded text-sm text-white focus:outline-none focus:border-green-500"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          type="submit"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          disabled={loading}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="w-full bg-green-600 hover:bg-green-700 text-white font-semibold py-2 rounded transition mt-2 text-sm disabled:opacity-50"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {loading ? 'প্রসেসিং...' : 'পেমেন্ট কনফার্ম করুন'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </form>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                